div.p:
OS page fault handler:
c
pfn = allocate_frame(phys_mem);
// pfn = 0x17 (example)
new_table = calloc(1024, sizeof(pte_t));
// All entries: valid = false

Update page directory entry:
c
pde[0x40].page_table_pfn = 0x17;
pde[0x40].present = true;
pde[0x40].writable = true;

Resume page table walk:
c
table_index = (va >> 12) & 0x3FF;
pte = page_table[0x17][table_index];
// pte.valid = false → page fault
// (allocate user data frame)
